"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[31275],{78103(e,t,i){i.r(t),i.d(t,{assets:()=>r,contentTitle:()=>h,default:()=>f,frontMatter:()=>n,metadata:()=>s,toc:()=>d});let s=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 16 Leases/definition-of-a-lease-decision-makin-aa1a02b69f","title":"Definition of a Lease\u2014Decision-making Rights (IFRS 16)","description":"January 2020","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 16 Leases/Definition of a Lease\u2014Decision-making Rights (IFRS 16).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 16 Leases","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/definition-of-a-lease-decision-makin-aa1a02b69f","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/definition-of-a-lease-decision-makin-aa1a02b69f","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"definition-of-a-lease-decision-makin-aa1a02b69f","title":"Definition of a Lease\u2014Decision-making Rights (IFRS 16)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/definition-of-a-lease-decision-makin-aa1a02b69f","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Training Costs to Fulfil a Contract (IFRS 15)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-and-ias-38-4724c9dbcc/training-costs-to-fulfil-a-contract--9acf8915cc"},"next":{"title":"Definition of a Lease\u2014Substitution Rights (IFRS 16","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/definition-of-a-lease-substitution-r-1bd7c8fed7"}}');var a=i(74848),o=i(28453);let n={id:"definition-of-a-lease-decision-makin-aa1a02b69f",title:"Definition of a Lease\u2014Decision-making Rights (IFRS 16)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/definition-of-a-lease-decision-makin-aa1a02b69f",sidebar_position:1},h="Definition of a Lease\u2014Decision-making Rights (IFRS 16)",r={},d=[{value:"The right to direct the use of an identified asset",id:"the-right-to-direct-the-use-of-an-identified-asset",level:2},{value:"The right to direct how and for what purpose an asset is used",id:"the-right-to-direct-how-and-for-what-purpose-an-asset-is-used",level:2}];function c(e){let t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,o.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"definition-of-a-leasedecision-making-rights-ifrs-16",children:"Definition of a Lease\u2014Decision-making Rights (IFRS 16)"})}),"\n",(0,a.jsx)(t.p,{children:"January 2020"}),"\n",(0,a.jsx)(t.p,{children:"The Committee received a request about whether the customer has the right to direct the use of a ship throughout the five-year term of a contract. In the fact pattern described in the request:"}),"\n",(0,a.jsx)(t.p,{children:"a. there is an identified asset (the ship) applying paragraphs B13\u2013B20 of IFRS 16.\nb. the customer has the right to obtain substantially all the economic benefits from use of the ship throughout the five-year period of use applying paragraphs B21\u2013B23 of IFRS 16.\nc. many, but not all, decisions about how and for what purpose the ship is used are predetermined in the contract. The customer has the right to make the remaining decisions about how and for what purpose the ship is used throughout the period of use. In the fact pattern described in the request, the customer has determined that this decision-making right is relevant because it affects the economic benefits to be derived from use of the ship.\nd. the supplier operates and maintains the ship throughout the period of use."}),"\n",(0,a.jsx)(t.h2,{id:"the-right-to-direct-the-use-of-an-identified-asset",children:"The right to direct the use of an identified asset"}),"\n",(0,a.jsx)(t.p,{children:"Paragraph B24 of IFRS 16 specifies when a customer has the right to direct the use of an identified asset throughout the period of use. Paragraph B24(b) applies only when the relevant decisions about how and for what purpose the asset is used are predetermined. The Board noted in paragraph BC121 of IFRS 16 that \u2018it would expect decisions about how and for what purpose an asset is used to be predetermined in relatively few cases\u2019."}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that, in the fact pattern described in the request, because not all relevant decisions about how and for what purpose the ship is used are predetermined, the customer considers paragraph B24(a) of IFRS 16 in assessing whether it has the right to direct the use of the ship."}),"\n",(0,a.jsx)(t.h2,{id:"the-right-to-direct-how-and-for-what-purpose-an-asset-is-used",children:"The right to direct how and for what purpose an asset is used"}),"\n",(0,a.jsx)(t.p,{children:"Paragraph B24(a) specifies that a customer has the right to direct the use of an identified asset throughout the period of use if it has \u2018the right to direct how and for what purpose the asset is used throughout the period of use (as described in paragraphs B25\u2013B30)\u2019."}),"\n",(0,a.jsx)(t.p,{children:"To have the right to direct how and for what purpose the asset is used, within the scope of its right of use defined in the contract, the customer must be able to change how and for what purpose the asset is used throughout the period of use (paragraph B25). In assessing whether that is the case, an entity considers rights to make decisions during the period of use that are most relevant to changing how and for what purpose the asset is used throughout that period. Decision-making rights are relevant when they affect the economic benefits to be derived from use (paragraph B25). An entity does not consider decisions that are predetermined before the period of use unless the conditions in paragraph B24(b)(ii) exist (paragraph B29)."}),"\n",(0,a.jsx)(t.p,{children:"Paragraph B26 includes examples of decision-making rights that, depending on the circumstances, grant the right to change how and for what purpose the asset is used. Rights limited to operating or maintaining the asset do not grant the right to change how and for what purpose it is used (paragraph B27)."}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that, in the fact pattern described in the request, the customer has the right to direct how and for what purpose the ship is used throughout the period of use. The customer has the right to make decisions about the use of the ship during the period of use that affect the economic benefits to be derived from that use. Therefore, within the scope of its right of use defined in the contract, the customer can change how and for what purpose the ship is used. The predetermination in the contract of many decisions about how and for what purpose the ship is used defines the scope of the customer\u2019s right of use\u2014within that scope, the customer has the right to make the decisions that are most relevant to changing how and for what purpose the ship is used. The Committee also observed that, although the operation and maintenance of the ship are essential to its efficient use, the supplier\u2019s decisions in this regard do not give it the right to direct how and for what purpose the ship is used."}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that, in the fact pattern described in the request, the customer has the right to direct the use of the ship throughout the period of use. Consequently, the contract contains a lease."}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IFRS 16 provide an adequate basis for an entity to determine whether the contract described in the request contains a lease. The Committee therefore decided not to add the matter to its standard-setting agenda."})]})}function f(e={}){let{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(c,{...e})}):c(e)}},28453(e,t,i){i.d(t,{R:()=>n,x:()=>h});var s=i(96540);let a={},o=s.createContext(a);function n(e){let t=s.useContext(o);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function h(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:n(e.components),s.createElement(o.Provider,{value:t},e.children)}}}]);